from typing import List

class Solution:
    def shortestSubstrings(self, arr: List[str]) -> List[str]:
        # Preprocess: collect all substrings from all other strings
        other_substrings = set()
        for i in range(len(arr)):
            for j in range(len(arr)):
                if i != j:
                    for k in range(len(arr[j])):
                        for l in range(k + 1, len(arr[j]) + 1):
                            other_substrings.add(arr[j][k:l])

        # For each string, find the shortest unique substring
        result = []
        for s in arr:
            found = False
            # Generate substrings of increasing length
            for length in range(1, len(s) + 1):
                candidates = []
                for i in range(len(s) - length + 1):
                    substr = s[i:i+length]
                    if substr not in other_substrings:
                        candidates.append(substr)
                if candidates:
                    # Return lexicographically smallest
                    result.append(min(candidates))
                    found = True
                    break
            if not found:
                result.append("")
        return result
